# Sadə set yaratma
numbers = {1, 2, 3, 4, 5}
fruits = {'alma', 'banan', 'nar'}
empty_set = set()
mixed = {1, 'hello', 3.14, (1, 2)}
print(numbers)
print(fruits)
print(empty_set)
print(mixed)

# Unikal elementlər və sırasızlıq
duplicates = {1, 2, 2, 3, 3, 4}
print(f'Təkrarlanmalar silindi: {duplicates}')
try:
    mixed = {1, [2, 3]}  # Siyahı dəyişkən olduğu üçün xəta verəcək
except TypeError:
    print('Xəta: Set-lər yalnız dəyişməz elementləri saxlaya bilər!')

# for dövrü ilə set
fruits = {'alma', 'banan', 'nar'}
for fruit in fruits:
    print(fruit)

// JavaScript kodu
const numbers = new Set([1, 2, 3]);
numbers.add(4);
console.log(numbers);

# Səhv idarəetməsi
numbers = {1, 2, 3}
try:
    numbers.remove(4)
except KeyError:
    print('Xəta: Element setdə yoxdur!')

try:
    numbers.add([4, 5])
except TypeError:
    print('Xəta: Set-lər dəyişkən elementləri saxlaya bilməz!')

