# Creating simple sets
numbers = {1, 2, 3, 4, 5}
fruits = {'apple', 'banana', 'orange'}
empty_set = set()
mixed = {1, 'hello', 3.14, (1, 2)}
print(numbers)
print(fruits)
print(empty_set)
print(mixed)

# Unique elements and unordered
duplicates = {1, 2, 2, 3, 3, 4}
print(f'Duplicates removed: {duplicates}')
try:
    mixed = {1, [2, 3]}  # Lists are mutable, so this raises an error
except TypeError:
    print('Error: Sets can only contain immutable elements!')

# Sets with for loop
fruits = {'apple', 'banana', 'orange'}
for fruit in fruits:
    print(fruit)

// JavaScript code
const numbers = new Set([1, 2, 3]);
numbers.add(4);
console.log(numbers);

# Error handling
numbers = {1, 2, 3}
try:
    numbers.remove(4)
except KeyError:
    print('Error: Element not found in set!')

try:
    numbers.add([4, 5])
except TypeError:
    print('Error: Sets cannot contain mutable elements!')

