# Создание простых множеств
numbers = {1, 2, 3, 4, 5}
fruits = {'яблоко', 'банан', 'апельсин'}
empty_set = set()
mixed = {1, 'привет', 3.14, (1, 2)}
print(numbers)
print(fruits)
print(empty_set)
print(mixed)

# Уникальные элементы и неупорядоченность
duplicates = {1, 2, 2, 3, 3, 4}
print(f'Дубликаты удалены: {duplicates}')
try:
    mixed = {1, [2, 3]}  # Список изменяемый, поэтому вызовет ошибку
except TypeError:
    print('Ошибка: Множества могут содержать только неизменяемые элементы!')

# Множества с циклом for
fruits = {'яблоко', 'банан', 'апельсин'}
for fruit in fruits:
    print(fruit)

// Код JavaScript
const numbers = new Set([1, 2, 3]);
numbers.add(4);
console.log(numbers);

# Обработка ошибок
numbers = {1, 2, 3}
try:
    numbers.remove(4)
except KeyError:
    print('Ошибка: Элемент не найден в множестве!')

try:
    numbers.add([4, 5])
except TypeError:
    print('Ошибка: Множества не могут содержать изменяемые элементы!')

